  1	import * as React from 'react';
  2	import { useSafeK8sWatchResource } from '@odf/core/hooks';
  3	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
  4	import { getName } from '@odf/shared/selectors';
  5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  6	import {
  7	  Dropdown,
  8	  DropdownItem,
  9	  DropdownList,
 10	  Divider,
 11	  MenuToggle,
 12	  MenuToggleElement,
 13	  Alert,
 14	} from '@patternfly/react-core';
 15	import { NamespacePolicyType } from '../../constants';
 16	import { namespaceStoreResource } from '../../resources';
 17	import { NamespaceStoreKind } from '../../types';
 18	import '../../style.scss';
 19	
 20	export const NamespaceStoreDropdown: React.FC<NamespaceStoreDropdownProps> = ({
 21	  namespace,
 22	  onChange,
 23	  className,
 24	  selectedKey,
 25	  enabledItems,
 26	  namespacePolicy,
 27	  creatorDisabled,
 28	  launchModal,
 29	}) => {
 30	  const { t } = useCustomTranslation();
 31	  const [isOpen, setOpen] = React.useState(false);
 32	  const [dropdownItems, setDropdownItems] = React.useState<JSX.Element[]>([]);
 33	
 34	  // Operator install namespace is determined using Subscriptions, which non-admin can not access.
 35	  // Using "true" in "useSafeK8sWatchResource" so that they can default to "openshift-storage" (if case of access issues),
 36	  // which is current use case as well (as we do not officially support UI if ODF is installed in any other Namespace).
 37	  // ToDo (Sanjal): Update the non-admin "Role" to a "ClusterRole", then read list of NamespaceStores across all namespaces.
 38	  const [nnsData, , nnsLoadErr] = useSafeK8sWatchResource<NamespaceStoreKind[]>(
 39	    namespaceStoreResource,
 40	    true
 41	  );
 42	  const noobaaNamespaceStores: NamespaceStoreKind[] = useDeepCompareMemoize(
 43	    nnsData,
 44	    true
 45	  );
 46	
 47	  React.useEffect(() => {
 48	    const nnsDropdownItems = noobaaNamespaceStores.reduce(
 49	      (res, nns) => {
 50	        const name = getName(nns);
 51	        res.push(
 52	          <DropdownItem
 53	            key={nns.metadata.uid}
 54	            component="button"
 55	            id={name}
 56	            isDisabled={
 57	              namespacePolicy === NamespacePolicyType.MULTI &&
 58	              !enabledItems.some((itemName) => itemName === name)
 59	            }
 60	            onClick={(e) =>
 61	              onChange(
 62	                noobaaNamespaceStores.find(
 63	                  (ns) => ns?.metadata?.name === e.currentTarget.id
 64	                )
 65	              )
 66	            }
 67	            data-test={`${name}-dropdown-item`}
 68	            description={t('Provider {{provider}} | Region: {{region}}', {
 69	              provider: nns?.spec?.type,
 70	              region: nns?.spec?.awsS3?.region,
 71	            })}
 72	          >
 73	            {name}
 74	          </DropdownItem>
 75	        );
 76	        return res;
 77	      },
 78	      creatorDisabled
 79	        ? []
 80	        : [
 81	            <DropdownItem
 82	              data-test="create-new-namespacestore-button"
 83	              key="first-item"
 84	              component="button"
 85	              onClick={launchModal}
 86	            >
 87	              {t('Create new NamespaceStore ')}
 88	            </DropdownItem>,
 89	            <Divider key="separator" />,
 90	          ]
 91	    );
 92	    setDropdownItems(nnsDropdownItems);
 93	  }, [
 94	    noobaaNamespaceStores,
 95	    t,
 96	    namespace,
 97	    creatorDisabled,
 98	    namespacePolicy,
 99	    enabledItems,
100	    onChange,
101	    launchModal,
102	  ]);
103	
104	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
105	    <MenuToggle
106	      ref={toggleRef}
107	      id="nns-dropdown-id"
108	      data-test="nns-dropdown-toggle"
109	      onClick={() => setOpen(!isOpen)}
110	      isExpanded={isOpen}
111	      isDisabled={
112	        !!nnsLoadErr ||
113	        (namespacePolicy === NamespacePolicyType.MULTI &&
114	          enabledItems?.length === 0)
115	      }
116	      isFullWidth
117	    >
118	      {selectedKey || t('Select a namespace store')}
119	    </MenuToggle>
120	  );
121	
122	  return (
123	    <div className={className}>
124	      {nnsLoadErr && (
125	        <Alert
126	          className="nb-create-bc-step-page--danger"
127	          variant="danger"
128	          isInline
129	          title={t('An error has occurred while fetching namespace stores')}
130	        />
131	      )}
132	      <Dropdown
133	        className="dropdown--full-width"
134	        isOpen={isOpen}
135	        onSelect={() => setOpen(false)}
136	        onOpenChange={(open: boolean) => setOpen(open)}
137	        toggle={toggle}
138	        popperProps={{ width: 'trigger' }}
139	      >
140	        <DropdownList>{dropdownItems}</DropdownList>
141	      </Dropdown>
142	    </div>
143	  );
144	};
145	
146	type NamespaceStoreDropdownProps = {
147	  id: string;
148	  namespace: string;
149	  onChange?: (NamespaceStoreKind) => void;
150	  className?: string;
151	  selectedKey: string;
152	  enabledItems?: string[];
153	  namespacePolicy?: NamespacePolicyType;
154	  creatorDisabled?: boolean;
155	  launchModal?: () => void;
156	};

